import React, { useState, useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import axios from 'axios';
import DashboardLayout from './components/DashboardLayout';
import Tasks from './pages/Tasks';
import Employees from './pages/Employees';
import Reports from './pages/Reports';

/**
 * Main App component
 */
function App() {
  const [stats, setStats] = useState({
    totalUsers: 0,
    activeProjects: 0,
    revenue: 0,
    systemHealth: 0
  });
  const [loading, setLoading] = useState(true);

  // Fetch dashboard stats on mount
  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/dashboard/stats');
        setStats(response.data);
      } catch (error) {
        console.error('Error fetching stats:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchStats();
  }, []);

  return (
    <DashboardLayout>
      <Routes>
        <Route path="/" element={
          <>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              <div className="bg-gray-800 p-4 rounded shadow">
                <h3 className="text-lg font-semibold">Total Users</h3>
                <p className="text-2xl">{loading ? 'Loading...' : stats.totalUsers}</p>
              </div>
              <div className="bg-gray-800 p-4 rounded shadow">
                <h3 className="text-lg font-semibold">Active Projects</h3>
                <p className="text-2xl">{loading ? 'Loading...' : stats.activeProjects}</p>
              </div>
              <div className="bg-gray-800 p-4 rounded shadow">
                <h3 className="text-lg font-semibold">Revenue</h3>
                <p className="text-2xl">{loading ? 'Loading...' : `$${stats.revenue}K`}</p>
              </div>
              <div className="bg-gray-800 p-4 rounded shadow">
                <h3 className="text-lg font-semibold">System Health</h3>
                <p className="text-2xl">{loading ? 'Loading...' : `${stats.systemHealth}%`}</p>
              </div>
            </div>
            <div className="bg-gray-800 p-4 rounded shadow">
              <h3 className="text-lg font-semibold mb-4">Charts and Data Table</h3>
              <p>Interactive charts and CRUD table will be added here.</p>
            </div>
          </>
        } />
        <Route path="/tasks" element={<Tasks />} />
        <Route path="/employees" element={<Employees />} />
        <Route path="/reports" element={<Reports />} />
      </Routes>
    </DashboardLayout>
  );
}

export default App;
